var _ marshaler.Event = RecalculateEvent{}

var recalculateEventType = metadata.EventType{
	Subsystem: EventSubsystem,
	Name:      RecalculateEventName,
	Version:   "v2",
}
var recalculateEventName = metadata.GetEventName(recalculateEventType)

func (e RecalculateEvent) EventName() string { return recalculateEventName }

func (e RecalculateEvent) Validate() error {
	var errs []error
	if e.AsOf.IsZero() {
		errs = append(errs, errors.New("asOf is required"))
	}
	if err := e.Entitlement.Validate(); err != nil {
		errs = append(errs, fmt.Errorf("entitlement: %w", err))
	}
	return errors.Join(errs...)
}

func NewNotificationsFilter(cfg NotificationsFilterConfig) (NamedFilter, error) {
	if err := cfg.Validate(); err != nil {
		return nil, err
	}
	filter := &NotificationsFilter{notificationService: cfg.NotificationService}
	ruleCache, err := lrux.NewCacheWithItemTTL(cfg.CacheSize, filter.fetchRulesForNamespace, lrux.WithTTL(cfg.CacheTTL))
	if err != nil {
		return nil, err
	}
	filter.ruleCache = ruleCache
	return filter, nil
}
